                high -= 0x60;
            }

            emulator.A = (byte)(low & 0b00001111 | high & 0b11110000);
        }
        else
        {
            emulator.A = (byte)binary_result;
            emulator.P &= 0x1C;
            if ((((left ^ right) & (binary_result ^ left) & 0b10000000) != 0x00))
            {
                emulator.P |= 0x40;
            }

